{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "活动规则配置",
  "type": "object",
  "properties": {
    "title": {
      "type": "string",
      "title": "页面标题",
      "default": "活动规则"
    },
    "rules": {
      "type": "array",
      "title": "规则列表",
      "items": {
        "type": "object",
        "properties": {
          "title": {
            "type": "string",
            "title": "规则标题"
          },
          "description": {
            "type": "string",
            "title": "规则说明",
            "ui:widget": "richtext"
          }
        },
        "required": ["title", "description"]
      },
      "default": [
        {
          "title": "参与资格",
          "description": "所有注册用户均可参与本次活动。用户需完成实名认证后方可领取奖品。"
        },
        {
          "title": "闯关规则",
          "description": "每关设有不同的任务目标，完成后可解锁下一关。关卡难度逐步递增，越往后奖励越丰厚。"
        },
        {
          "title": "积分机制",
          "description": "每完成一关可获得对应积分，积分可用于抽奖转盘和兑换奖品。连续通关可获得额外加成积分。"
        }
      ]
    },
    "showBackButton": {
      "type": "boolean",
      "title": "显示返回按钮",
      "default": true
    },
    "accentColor": {
      "type": "string",
      "format": "color",
      "title": "强调色",
      "default": "#8B5CF6"
    }
  },
  "required": ["title"]
}

import { useState } from 'react';
import { ChevronDown, ChevronUp, ArrowLeft, CheckCircle, Star, Shield, Zap, Sparkles } from 'lucide-react';

interface RuleItem {
  title: string;
  description: string;
}

interface DemoProps {
  title: string;
  rules: RuleItem[];
  showBackButton: boolean;
  accentColor: string;
}

const ruleIcons = [CheckCircle, Star, Shield, Zap, Sparkles];
const ruleColors = ['from-emerald-400 to-emerald-500', 'from-amber-400 to-amber-500', 'from-violet-400 to-violet-500', 'from-blue-400 to-blue-500', 'from-rose-400 to-rose-500'];

export default function Demo({
  title = '活动规则',
  rules = [],
  showBackButton = true,
  accentColor = '#8B5CF6',
}: DemoProps) {
  const [expandedIndex, setExpandedIndex] = useState<number | null>(0);

  const toggleExpand = (index: number) => {
    setExpandedIndex(expandedIndex === index ? null : index);
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-violet-50 via-white to-white">
      {/* Top Gradient Decoration */}
      <div
        className="h-2 w-full"
        style={{
          background: `linear-gradient(90deg, ${accentColor}, #A78BFA, #60A5FA)`,
        }}
      />

      {/* Header */}
      <div className="relative px-4 pt-4 pb-2">
        {showBackButton && (
          <button className="w-8 h-8 rounded-full bg-white shadow-sm flex items-center justify-center mb-3">
            <ArrowLeft className="w-4 h-4 text-gray-600" />
          </button>
        )}
        <h1 className="text-2xl font-bold text-gray-900">{title}</h1>
        <p className="text-sm text-gray-400 mt-1">请仔细阅读以下活动规则</p>
      </div>

      {/* Rules List */}
      <div className="px-4 pt-2 pb-24 space-y-3">
        {rules.map((rule, index) => {
          const isExpanded = expandedIndex === index;
          const IconComp = ruleIcons[index % ruleIcons.length];
          const colorClass = ruleColors[index % ruleColors.length];

          return (
            <div
              key={index}
              className="bg-white rounded-2xl shadow-sm border border-gray-50 overflow-hidden transition-all duration-200"
            >
              <button
                onClick={() => toggleExpand(index)}
                className="w-full flex items-center gap-3 p-4 text-left"
              >
                {/* Icon */}
                <div
                  className={`w-10 h-10 rounded-xl bg-gradient-to-br ${colorClass} flex items-center justify-center flex-shrink-0 shadow-sm`}
                >
