        { "name": "二等奖 蓝牙耳机", "color": "#F97316", "icon": "headphones" },
        { "name": "三等奖 优惠券", "color": "#EAB308", "icon": "ticket" },
        { "name": "四等奖 积分", "color": "#22C55E", "icon": "coins" },
        { "name": "谢谢参与", "color": "#6B7280", "icon": "meh" },
        { "name": "幸运奖 小礼品", "color": "#EC4899", "icon": "heart" }
      ]
    },
    "remainingDraws": {
      "type": "number",
      "title": "剩余抽奖次数",
      "default": 3,
      "minimum": 0,
      "maximum": 99
    },
    "primaryColor": {
      "type": "string",
      "format": "color",
      "title": "主色调",
      "default": "#EF4444"
    },
    "spinDuration": {
      "type": "number",
      "title": "旋转时长(秒)",
      "default": 3,
      "minimum": 1,
      "maximum": 8
    }
  },
  "required": ["title"]
}

import React, { useState, useCallback } from 'react';
import { Gift, Sparkles, RotateCw, Trophy, Headphones, Ticket, Coins, Heart, Meh } from 'lucide-react';

interface Prize {
  name: string;
  color: string;
  icon: string;
}

interface DemoProps {
  title: string;
  prizes: Prize[];
  remainingDraws: number;
  primaryColor: string;
  spinDuration: number;
}

const iconMap: Record<string, React.ReactNode> = {
  gift: <Gift className="w-5 h-5" />,
  headphones: <Headphones className="w-5 h-5" />,
  ticket: <Ticket className="w-5 h-5" />,
  coins: <Coins className="w-5 h-5" />,
  meh: <Meh className="w-5 h-5" />,
  heart: <Heart className="w-5 h-5" />,
};

function getRandomPrize(prizes: Prize[]): number {
  // Weighted random - less likely to get "谢谢参与"
  const weights = prizes.map((p) => (p.name.includes('谢谢') ? 1 : 3));
  const total = weights.reduce((a, b) => a + b, 0);
  let r = Math.random() * total;
  for (let i = 0; i < prizes.length; i++) {
    r -= weights[i];
    if (r <= 0) return i;
  }
  return 0;
}

export default function Demo({
  title,
  prizes,
  remainingDraws: initialDraws,
  primaryColor,
  spinDuration,
}: DemoProps) {
  const [rotation, setRotation] = useState(0);
  const [spinning, setSpinning] = useState(false);
  const [drawsLeft, setDrawsLeft] = useState(initialDraws);
  const [result, setResult] = useState<string | null>(null);
  const [showResult, setShowResult] = useState(false);

  const segmentAngle = 360 / prizes.length;

  const handleSpin = useCallback(() => {
    if (spinning || drawsLeft <= 0) return;

    setSpinning(true);
    setResult(null);
    setShowResult(false);

    const winIndex = getRandomPrize(prizes);
    // Calculate target rotation: multiple full spins + land on correct segment
    const targetSegment = 360 - winIndex * segmentAngle - segmentAngle / 2;
    const fullSpins = 5 * 360;
    const newRotation = rotation + fullSpins + targetSegment - (rotation % 360);
    setRotation(newRotation);

    setTimeout(() => {
      setSpinning(false);
      setResult(prizes[winIndex].name);
      setShowResult(true);
      setDrawsLeft((d) => Math.max(0, d - 1));
    }, spinDuration * 1000);
  }, [spinning, drawsLeft, rotation, prizes, segmentAngle, spinDuration]);

  const closeResult = () => setShowResult(false);

  return (
    <div className="min-h-screen bg-gradient-to-b from-red-50 to-orange-50 p-4">
      {/* Header */}
      <div className="text-center mb-6">
        <h1 className="text-2xl font-bold text-gray-800">{title}</h1>
        <p className="text-sm text-gray-500 mt-1">转动转盘，赢取好礼</p>
      </div>

      {/* Draws remaining */}
      <div className="flex justify-center mb-4">
        <div className="bg-white rounded-full px-6 py-2 shadow-md flex items-center gap-2">
          <RotateCw className="w-4 h-4 text-red-500" />
          <span className="text-sm font-medium text-gray-700">
            剩余抽奖次数：
          </span>
          <span className="text-lg font-bold" style={{ color: primaryColor }}>
            {drawsLeft}
          </span>
        </div>
      </div>

      {/* Wheel */}
      <div className="flex justify-center mb-4">
        <div className="relative" style={{ width: 300, height: 300 }}>
          {/* Outer ring */}
          <div
            className="absolute inset-0 rounded-full shadow-xl border-4 border-white"
            style={{
              background: `conic-gradient(${prizes
                .map(
                  (p, i) =>
                    `${p.color} ${(i * 360) / prizes.length}deg ${((i + 1) * 360) / prizes.length}deg`
